import{c as t,S as o,j as a,m as n}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"Troubleshooting Sharing","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/troubleshooting.md","filePath":"sharing/troubleshooting.md","lastUpdated":1783409445000}'),i={name:"sharing/troubleshooting.md"};function r(s,e,l,h,d,c){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="troubleshooting-sharing" tabindex="-1">Troubleshooting Sharing <a class="header-anchor" href="#troubleshooting-sharing" aria-label="Permalink to “Troubleshooting Sharing”">​</a></h1><h2 id="the-link-404s-for-my-teammate-—-it-s-access-not-a-broken-link" tabindex="-1">&quot;The link 404s for my teammate&quot; — it&#39;s access, not a broken link <a class="header-anchor" href="#the-link-404s-for-my-teammate-—-it-s-access-not-a-broken-link" aria-label="Permalink to “&quot;The link 404s for my teammate&quot; — it&#39;s access, not a broken link”">​</a></h2><p>This is the single most common confusion, so it comes first: <strong>publishing a bundle does not grant anyone access to it.</strong> If the bundle lives in a private GitHub repo, the link answers 404 to anyone without read access — GitHub deliberately does not distinguish &quot;doesn&#39;t exist&quot; from &quot;no permission&quot;.</p><p>Fixes, in order of preference:</p><ol><li><strong>Team setup</strong>: host bundles in an organization-owned repo with base permission Read — every org member has access automatically. See <a href="./index#the-recommended-team-setup-an-organization-shelf">the org shelf</a>.</li><li><strong>Individual</strong>: invite the person as a repository collaborator (repo → Settings → Collaborators), and have them retry after accepting.</li><li>The receiver must also be <em>authenticated</em> when downloading: <code>gh auth login</code> for the CLI path, or a logged-in browser for the manual path.</li></ol><h2 id="gh-is-not-installed" tabindex="-1">&quot;gh is not installed&quot; <a class="header-anchor" href="#gh-is-not-installed" aria-label="Permalink to “&quot;gh is not installed&quot;”">​</a></h2><p><code>gh</code> is only needed for <strong>private</strong> sources. Either install it (<a href="https://cli.github.com" target="_blank" rel="noreferrer">cli.github.com</a>) and run <code>gh auth login</code>, or use the browser fallback: download the zip from the release page, then <code>knowlery bundle install &lt;local-file&gt;</code>.</p><h2 id="integrity-check-failed" tabindex="-1">&quot;Integrity check failed&quot; <a class="header-anchor" href="#integrity-check-failed" aria-label="Permalink to “&quot;Integrity check failed&quot;”">​</a></h2><p>The downloaded bytes don&#39;t match the <code>--verify</code> checksum. Possible causes: the sharer updated the asset after posting the hash, the wrong asset was linked, or the transfer was tampered with. Ask the sharer to re-post the current hash; nothing was installed.</p><h2 id="download-failed-http-404-from-a-non-github-url" tabindex="-1">&quot;Download failed: HTTP 404&quot; from a non-GitHub URL <a class="header-anchor" href="#download-failed-http-404-from-a-non-github-url" aria-label="Permalink to “&quot;Download failed: HTTP 404&quot; from a non-GitHub URL”">​</a></h2><p>The URL simply doesn&#39;t serve a file. Common with file-sharing services whose &quot;share links&quot; open a web page instead of the file — you need a <strong>direct download</strong> link that serves the zip bytes.</p>',11)])])}const m=t(i,[["render",r]]);export{g as __pageData,m as default};
